import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import Sidebar from '../components/Sidebar';
import '../styles/CalendarPage.css';

function CalendarPage({ user, onLogout }) {
  const navigate = useNavigate();
  const [tasks, setTasks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [currentMonth, setCurrentMonth] = useState(new Date());

  useEffect(() => {
    fetchAllTasks();
  }, []);

  const fetchAllTasks = async () => {
    try {
      const token = localStorage.getItem('token');
      const boardsResponse = await axios.get('/api/boards', {
        headers: { Authorization: `Bearer ${token}` }
      });

      let allTasks = [];
      for (const board of boardsResponse.data) {
        const tasksResponse = await axios.get(`/api/tasks/board/${board._id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        allTasks = [...allTasks, ...tasksResponse.data];
      }

      setTasks(allTasks);
      setError('');
    } catch (err) {
      setError('Failed to fetch tasks');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    onLogout();
    navigate('/');
  };

  const getDaysInMonth = (date) => {
    return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
  };

  const getFirstDayOfMonth = (date) => {
    return new Date(date.getFullYear(), date.getMonth(), 1).getDay();
  };

  const renderCalendar = () => {
    const daysInMonth = getDaysInMonth(currentMonth);
    const firstDay = getFirstDayOfMonth(currentMonth);
    const days = [];

    for (let i = 0; i < firstDay; i++) {
      days.push(<div key={`empty-${i}`} className="empty-day"></div>);
    }

    for (let i = 1; i <= daysInMonth; i++) {
      const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), i);
      const dayTasks = tasks.filter(task => {
        if (!task.dueDate) return false;
        const taskDate = new Date(task.dueDate);
        return (
          taskDate.getDate() === i &&
          taskDate.getMonth() === currentMonth.getMonth() &&
          taskDate.getFullYear() === currentMonth.getFullYear()
        );
      });

      days.push(
        <div key={i} className={`calendar-day ${dayTasks.length > 0 ? 'has-tasks' : ''}`}>
          <div className="day-number">{i}</div>
          <div className="day-tasks">
            {dayTasks.slice(0, 2).map(task => (
              <div key={task._id} className="task-indicator">
                {task.title.substring(0, 10)}...
              </div>
            ))}
            {dayTasks.length > 2 && <div className="more-tasks">+{dayTasks.length - 2}</div>}
          </div>
        </div>
      );
    }

    return days;
  };

  const handleLogout2 = () => {
    onLogout();
    navigate('/');
  };

  if (loading) {
    return <div className="loading">Loading calendar...</div>;
  }

  return (
    <div className="app-container">
      <Sidebar user={user} onLogout={handleLogout2} currentPage="calendar" />

      <div className="main-content">
        <header className="header">
          <h1>TaskFlow - Calendar</h1>
          <div className="header-content">
            <input type="text" className="search-bar" placeholder="Search tasks..." />
          </div>
          <div className="auth-buttons">
            <button className="btn btn-danger" onClick={handleLogout}>
              Logout
            </button>
          </div>
        </header>

        <div className="page-content">
          {error && <div className="error-message">{error}</div>}

          <div className="calendar-container">
            <div className="calendar-header">
              <button
                onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1))}
              >
                Previous
              </button>
              <h2>
                {currentMonth.toLocaleString('default', { month: 'long', year: 'numeric' })}
              </h2>
              <button
                onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1))}
              >
                Next
              </button>
            </div>

            <div className="calendar-weekdays">
              <div className="weekday">Sun</div>
              <div className="weekday">Mon</div>
              <div className="weekday">Tue</div>
              <div className="weekday">Wed</div>
              <div className="weekday">Thu</div>
              <div className="weekday">Fri</div>
              <div className="weekday">Sat</div>
            </div>

            <div className="calendar-days">
              {renderCalendar()}
            </div>

            <div className="upcoming-tasks">
              <h3>Upcoming Tasks</h3>
              <div className="tasks-list">
                {tasks
                  .filter(task => task.dueDate && new Date(task.dueDate) >= new Date())
                  .sort((a, b) => new Date(a.dueDate) - new Date(b.dueDate))
                  .slice(0, 10)
                  .map(task => (
                    <div key={task._id} className="upcoming-task-item">
                      <div className="task-info">
                        <h4>{task.title}</h4>
                        <p>{new Date(task.dueDate).toLocaleDateString()}</p>
                      </div>
                      <div className={`task-status status-${task.status}`}>
                        {task.status}
                      </div>
                    </div>
                  ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default CalendarPage;
